        function renderFuncResults(results) {
            var area = document.getElementById('funcResultArea');
            var html = '<table class="result-table"><thead><tr><th>功能</th><th>支持</th><th>最小值</th><th>最大值</th><th>当前值</th><th>状态</th></tr></thead><tbody>';
            var keys = Object.keys(results);
            if (keys.length === 0) {
                html += '<tr><td colspan="6" style="text-align:center;color:#6e7681">暂无结果</td></tr>';
            } else {
                keys.forEach(function(key) {
                    var item = results[key];
                    var supported = item.supported ? '<span class="badge yes">✅</span>' : '<span class="badge no">❌</span>';
                    var status = item.status || '完成';
                    html += '<tr>';
                    html += '<td>' + key + '</td>';
                    html += '<td>' + supported + '</td>';
                    html += '<td>' + (item.min_value != null ? item.min_value : '--') + '</td>';
                    html += '<td>' + (item.max_value != null ? item.max_value : '--') + '</td>';
                    html += '<td>' + (item.current_value != null ? item.current_value : '--') + '</td>';
                    html += '<td><span class="badge yes">' + status + '</span></td>';
                    html += '</tr>';
                });
            }
            html += '</tbody></table>';
            area.innerHTML = html;
        }
        // ================================================================
        //  Limit Test (P6.0-P6.4)
        // ================================================================
        function limitTestRun() {
            if (!window.connectedDevice || !window.connectedDevice.ip) { showToast('warning', '请先在「设备管理」中连接设备'); return; }
            var deviceIp = window.connectedDevice.ip;
            var device = window.connectedDevice;
            var btn = document.getElementById('btnLimitRun');
            btn.disabled = true;
            btn.innerHTML = '<span class="spinner" style="display:inline-block"></span> 测试中...';
            document.getElementById('limitProgress').style.display = 'block';
            document.getElementById('limitDirection').style.display = 'block';
            document.getElementById('limitResultArea').innerHTML = '';
            addLog('info', '限位测试开始: ' + deviceIp);
            apiPost('/api/v1/advanced/limit/run', {
                device_ip: deviceIp,
                username: (device && device.username) || 'admin',
                password: (device && device.password) || '',
                port: (device && device.port) || 80
            }).then(function(resp) {
                btn.disabled = false;
                btn.innerHTML = '▶ 开始测试';
                document.getElementById('limitProgress').style.display = 'none';
                document.getElementById('limitDirection').style.display = 'none';
                if (resp && resp.success) {
                    showToast('success', '限位测试完成');
                    addLog('success', '限位测试完成: ' + (resp.message || ''));
                    renderLimitResults(resp.results || {});
                } else {
                    showToast('error', resp ? resp.message : '测试失败');
                    addLog('error', '限位测试失败: ' + (resp ? resp.message : '未知'));
                }
            }).catch(function(e) {
                btn.disabled = false;
                btn.innerHTML = '▶ 开始测试';
                document.getElementById('limitProgress').style.display = 'none';
                document.getElementById('limitDirection').style.display = 'none';
                showToast('error', '测试异常: ' + e.message);
            });
            // Progress bar: real status (no hardcoded simulation)
            var limitProgText = document.getElementById('limitProgressText');
            var limitProgBar = document.getElementById('limitProgressBar');
            var limitDirEl = document.getElementById('limitDirection');
            if (limitProgText) limitProgText.textContent = '测试中... 等待设备响应';
            if (limitProgBar) limitProgBar.style.width = '30%';
            if (limitDirEl) { limitDirEl.textContent = '当前方向: 初始化...'; limitDirEl.style.display = 'block'; }
            // simulateProgress/simulateDirections REMOVED - hardcoded fake progress
        }
        function renderLimitResults(results) {
            var area = document.getElementById('limitResultArea');
            if (!results || Object.keys(results).length === 0) {
                area.innerHTML = '<div class="advanced-status-panel"><p style="color:#6e7681">暂无结果</p></div>';
                return;
            }
            var html = '<div class="advanced-status-panel"><h4>限位测试结果</h4>';
            // P axis
            var pLimit = results.pan_range || results.p_limit || [0, 3600];
            var tLimit = results.tilt_range || results.t_limit || [-200, 900];
            html += '<div class="status-row"><span class="status-label">P轴限位</span><span class="status-value">' + pLimit[0] + ' ~ ' + pLimit[1] + '</span></div>';
            html += '<div class="status-row"><span class="status-label">T轴限位</span><span class="status-value">' + tLimit[0] + ' ~ ' + tLimit[1] + '</span></div>';
            html += '<div class="status-row"><span class="status-label">翻转</span><span class="status-value">' + (results.flip ? '有' : '无') + '</span></div>';
            html += '<div class="status-row"><span class="status-label">稳定性</span><span class="status-value">' + (results.stable ? '<span class="badge yes">✅ 稳定</span>' : '<span class="badge no">❌ 不稳定</span>') + '</span></div>';
            if (results.csv_path) {
                html += '<div class="status-row"><span class="status-label">CSV 路径</span><span class="status-value">' + results.csv_path + '</span></div>';
            }
            html += '</div>';
            area.innerHTML = html;
        }
        // ================================================================
        //  Speed Test (P5.4 + M4 P3)
        // ================================================================
        function speedTestRun() {
            if (!window.connectedDevice || !window.connectedDevice.ip) { showToast('warning', '请先在「设备管理」中连接设备'); return; }
            var deviceIp = window.connectedDevice.ip;
            var device = window.connectedDevice;
            var btn = document.getElementById('btnSpeedRun');
            btn.disabled = true;
            btn.innerHTML = '<span class="spinner" style="display:inline-block"></span> 测试中...';
            document.getElementById('speedProgress').style.display = 'block';
            document.getElementById('speedResultArea').innerHTML = '';
            addLog('info', '速度测试开始: ' + deviceIp);
            apiPost('/api/v1/advanced/speed/run', {
                device_ip: deviceIp,
                username: (device && device.username) || 'admin',
                password: (device && device.password) || '',
                port: (device && device.port) || 80
            }).then(function(resp) {
                btn.disabled = false;
                btn.innerHTML = '▶ 开始测试';
                document.getElementById('speedProgress').style.display = 'none';
                if (resp && resp.success) {
                    showToast('success', '速度测试完成');
                    addLog('success', '速度测试完成: ' + (resp.message || ''));
                    renderSpeedResults(resp.results || {});
                } else {
                    showToast('error', resp ? resp.message : '测试失败');
                    addLog('error', '速度测试失败: ' + (resp ? resp.message : '未知'));
                }
            }).catch(function(e) {
                btn.disabled = false;
                btn.innerHTML = '▶ 开始测试';
                document.getElementById('speedProgress').style.display = 'none';
                showToast('error', '测试异常: ' + e.message);
            });
            // Progress bar: real status (no hardcoded speed labels)
            var speedProgText = document.getElementById('speedProgressText');
            var speedProgBar = document.getElementById('speedProgressBar');
            if (speedProgText) speedProgText.textContent = '测试中... 等待设备响应';
            if (speedProgBar) speedProgBar.style.width = '30%';
            // REMOVED simulateProgress (was hardcoded: '速度档位 1', '50', '100')
            // Speed results now display actual values returned from backend
        }
        function renderSpeedResults(results) {
            var area = document.getElementById('speedResultArea');
            if (!results || Object.keys(results).length === 0) {
                area.innerHTML = '<div class="advanced-status-panel"><p style="color:#6e7681">暂无结果</p></div>';
                return;
            }
            var html = '<div class="advanced-status-panel"><h4>速度测试结果</h4>';
            // Speed mapping table
            var speedMap = results.speed_map || results.speed_mapping || {};
            var mapKeys = Object.keys(speedMap);
            if (mapKeys.length > 0) {
                html += '<table class="result-table" style="margin:12px 0"><thead><tr><th>速度档位</th><th>实际速率 (°/s)</th></tr></thead><tbody>';
                mapKeys.forEach(function(k) {
                    html += '<tr><td>' + k + '</td><td>' + speedMap[k] + '</td></tr>';
                });
                html += '</tbody></table>';
            }
            html += '<div class="status-row"><span class="status-label">拟合曲线 R²</span><span class="status-value">' + (results.r_squared || results.r2 || '--') + '</span></div>';
            html += '<div class="status-row"><span class="status-label">精度</span><span class="status-value">' + (results.accuracy || '--') + '</span></div>';
            html += '<div class="status-row"><span class="status-label">通过</span><span class="status-value">' + (results.passed ? '<span class="badge yes">✅</span>' : '<span class="badge no">❌</span>') + '</span></div>';
            html += '</div>';
            area.innerHTML = html;
        }
        // ================================================================
        //  Progress Simulation
        // ================================================================
        function simulateProgress(textId, barId, totalSteps, labels) {
            var current = 0;
            var interval = setInterval(function() {
                current++;
                if (current > totalSteps) { clearInterval(interval); return; }
                var pct = Math.round((current / totalSteps) * 100);
                var textEl = document.getElementById(textId);
                var barEl = document.getElementById(barId);
                if (textEl) textEl.textContent = labels ? labels[current-1] : '处理中... ' + current + '/' + totalSteps;
                if (barEl) barEl.style.width = pct + '%';
            }, 2000);
        }
        function simulateDirections() {
            var dirs = ['P+ 移动中...', 'P- 移动中...', 'T+ 移动中...', 'T- 移动中...'];
            var i = 0;
            var interval = setInterval(function() {
                var el = document.getElementById('limitDirection');
                if (!el) { clearInterval(interval); return; }
                if (i >= dirs.length) { clearInterval(interval); el.textContent = '测试完成 ✓'; el.style.color = '#3fb950'; return; }
                el.textContent = '当前方向: ' + dirs[i];
                i++;
            }, 3000);
        }
