// 加载锐度
function loadSharpness(deviceIp) {
    apiGet('/api/v1/ptz/' + deviceIp + '/image/sharpness').then(function(r) {
        if (r && r.success && r.data) {
            var sp = r.data;
            deviceImageParams.sharpness = sp;

            var slider = document.getElementById('consoleSharpness');
            var range = document.getElementById('sharpnessRange');

            if (slider) {
                slider.min = sp.min || 0;
                slider.max = sp.max || 100;
                slider.value = sp.current_level || 50;
            }
            if (range) {
                range.textContent = '(' + (sp.min || 0) + '~' + (sp.max || 100) + ')';
            }
        }
    }).catch(function(e) {
        console.warn('[Sharpness] Load failed:', e);
    });
}

// 加载亮度/对比度/饱和度
function loadColorParams(deviceIp) {
    apiGet('/api/v1/ptz/' + deviceIp + '/image/color').then(function(r) {
        if (r && r.success && r.data) {
            var c = r.data;
            deviceImageParams.color = c;

            var brightness = document.getElementById('consoleBrightness');
            var contrast = document.getElementById('consoleContrast');
            var saturation = document.getElementById('consoleSaturation');

            if (brightness && c.brightness !== undefined) brightness.value = c.brightness;
            if (contrast && c.contrast !== undefined) contrast.value = c.contrast;
            if (saturation && c.saturation !== undefined) saturation.value = c.saturation;
        }
    }).catch(function(e) {
        console.warn('[Color] Load failed:', e);
    });
}

// ==================== 设置函数 ====================

// 设置锐度
function setSharpness(value) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;
    apiPost('/api/v1/ptz/' + dev + '/image/sharpness', { level: parseInt(value) });
}

// 设置白平衡模式
function setWhiteBalanceMode(mode) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;

    // v5.40: 处理三种模式
    var actualMode = mode;
    if (mode === 'auto_official') {
        actualMode = 'auto';
    } else if (mode === 'auto_astrohub') {
        // 暂未实现
        showToast('warning', '自动暂未实现');
        return;
    }

    apiPost('/api/v1/ptz/' + dev + '/image/whitebalance', { mode: actualMode })
        .then(function(r) {
            if (r && r.success) {
                showToast('success', '白平衡: ' + (actualMode === 'auto' ? '自动（官方）' : '手动'));
                // v5.40: 更新 R/B 滑动条状态
                var wbRed = document.getElementById('wbRed');
                var wbBlue = document.getElementById('wbBlue');
                if (wbRed) wbRed.disabled = actualMode !== 'manual';
                if (wbBlue) wbBlue.disabled = actualMode !== 'manual';
            }
        });
}

// 设置白平衡增益 R/B
function setWhiteBalanceGain(channel, value) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;

    // 更新显示
    if (channel === 'red') {
        var el = document.getElementById('wbRedVal');
        if (el) el.textContent = value;
    } else {
        var el = document.getElementById('wbBlueVal');
        if (el) el.textContent = value;
    }

    // 发送请求
    var key = channel === 'red' ? 'red_gain' : 'blue_gain';
    apiPost('/api/v1/ptz/' + dev + '/image/whitebalance', { [key]: parseInt(value) });
}

// 设置降噪
function setNoiseReduce(type, value) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;

    // 更新显示
    var el = document.getElementById(type === 'spatial' ? 'dnrSpatialVal' : 'dnrTemporalVal');
    if (el) el.textContent = value;

    // 发送请求
    var key = type === 'spatial' ? 'spatial_level' : 'temporal_level';
    apiPost('/api/v1/ptz/' + dev + '/image/noisereduce', { [key]: parseInt(value) });
}

// 设置快门
function setShutterSpeed(value) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;

    if (value === 'auto') {
        apiPost('/api/v1/ptz/' + dev + '/image/shutter', { mode: 'auto' });
    } else {
        apiPost('/api/v1/ptz/' + dev + '/image/shutter', { level: value })
            .then(function(r) {
                if (r && r.success) showToast('success', '快门: ' + value);
            });
    }
}

// 设置光圈
function setIris(value) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
