    """使用 netsh 临时禁用指定网卡."""
    try:
        result = subprocess.run(
            ['netsh', 'interface', 'set', 'interface', name, 'disable'],
            capture_output=True, text=True, timeout=15, check=False,
        )
        if result.returncode == 0:
            print(f"[SADP] 已临时禁用虚拟网卡: {name}")
            return True
        else:
