function loadDeviceImageParams(deviceIp) {
    if (!deviceIp) return;

    // 检查 apiGet 是否可用
    if (typeof apiGet === 'undefined') {
        console.error('[IMAGE] apiGet not defined, cannot load image params');
        return;
    }

    console.log('[IMAGE] Loading image params for:', deviceIp);

    // v6.0: 先尝试从后端缓存获取
    apiGet('/api/v1/ptz/image-params').then(function(r) {
        if (r && r.success && r.params && Object.keys(r.params).length > 0) {
            console.log('[v6.0] 使用缓存参数');
            applyCachedParams(r.params);
            return; // 使用缓存，不再从设备读取
        }
        // 缓存为空，从设备读取
        loadParamsFromDevice(deviceIp);
    }).catch(function(e) {
        console.warn('[v6.0] 缓存获取失败，从设备读取:', e);
        loadParamsFromDevice(deviceIp);
    });
}

// v6.0: 从缓存参数应用到 UI
function applyCachedParams(params) {
    if (params.exposureMode) {
        var sel = document.getElementById('exposureMode');
        if (sel) sel.value = params.exposureMode;
        updateShutterIrisState(params.exposureMode);
    }
    if (params.shutter) {
        var sh = params.shutter;
        var sel = document.getElementById('shutterSelect');
        if (sel && sh.current_level) sel.value = sh.current_level;
    }
    if (params.iris) {
        var ir = params.iris;
        var slider = document.getElementById('irisSlider');
        var val = document.getElementById('irisVal');
        if (slider && ir.current_level) slider.value = ir.current_level;
        if (val && ir.current_level) val.textContent = ir.current_level;
    }
    if (params.whitebalance) {
        var wb = params.whitebalance;
        var modeSel = document.getElementById('whiteBalanceMode');
        if (modeSel && wb.mode) modeSel.value = wb.mode;
        var rSlider = document.getElementById('wbRedSlider');
        var bSlider = document.getElementById('wbBlueSlider');
        if (rSlider && wb.red_gain != null) rSlider.value = wb.red_gain;
        if (bSlider && wb.blue_gain != null) bSlider.value = wb.blue_gain;
    }
}

// v6.0: 从设备读取参数（原有逻辑）
function loadParamsFromDevice(deviceIp) {
    // v5.42: 先加载 function.json 获取参数范围
    apiGet('/api/v1/ptz/' + deviceIp + '/function').then(function(r) {
        if (r && r.success && r.data) {
            deviceFunctionData = r.data;
            console.log('[IMAGE] function.json loaded:', r.data.functions);
        }
    }).catch(function(e) {
        console.warn('[IMAGE] function.json load failed:', e);
    });

    // 加载曝光模式
    loadExposure(deviceIp);

    // 加载 OSD 状态
    loadOsdStatus(deviceIp);

    // 加载白平衡
    loadWhiteBalance(deviceIp);

    // 加载降噪
    loadNoiseReduce(deviceIp);

    // 加载快门
    loadShutter(deviceIp);

    // 加载光圈
    loadIris(deviceIp);

    // 加载锐度
    loadSharpness(deviceIp);

    // 加载亮度/对比度/饱和度
    loadColorParams(deviceIp);
}

