// v6.0: 从后端恢复连接状态
function restoreConnectionState() {
    apiGet('/api/v1/ptz/connected').then(function(r) {
        if (r && r.success && r.connected && r.device) {
            window.connectedDevice = r.device;
            console.log('[v6.0] 已恢复连接:', r.device.ip);
            // v6.0: 自动触发 WASM 登录（凭据已从后端获取）
            if (window.clickLogin2 && r.device.username && r.device.password) {
                setTimeout(function() { window.clickLogin2(); }, 500);
            }
        }
    }).catch(function(e) {
        console.warn('[v6.0] 获取连接状态失败:', e);
    });
}

