@api_router.get("/ptz/connected", summary="获取已连接设备状态 (v6.0)", tags=["PTZ"])
async def get_connected_device() -> dict:
    """v6.0: 从 ptz_config.json 获取当前连接的设备信息。"""
    mgr: PTZManager | None = _managers.get("ptz_manager")  # type: ignore[assignment]
    if not mgr:
        return {"success": False, "message": "PTZManager 未初始化", "connected": False}
    device = mgr.get_connected_device()
    if not device:
        return {"success": True, "connected": False, "device": None}
    return {"success": True, "connected": True, "device": device}

