@api_router.get("/ptz/connected", summary="获取已连接设备状态 (v6.0)", tags=["PTZ"])
async def get_connected_device() -> dict:
    """v6.0: 获取当前连接的设备信息和缓存的图像参数。"""
    mgr: PTZManager | None = _managers.get("ptz_manager")  # type: ignore[assignment]
    if not mgr:
        return {"success": False, "message": "PTZManager 未初始化", "connected": False}
    device = mgr.get_connected_device()
    if not device:
        return {"success": True, "connected": False, "device": None}
    return {"success": True, "connected": True, "device": device}


@api_router.get("/ptz/image-params", summary="获取缓存图像参数 (v6.0)", tags=["PTZ"])
async def get_cached_image_params() -> dict:
    """v6.0: 获取缓存的图像参数，避免刷新后重新读取设备。"""
    mgr: PTZManager | None = _managers.get("ptz_manager")  # type: ignore[assignment]
    if not mgr:
        return {"success": False, "message": "PTZManager 未初始化"}
    device = mgr.get_connected_device()
    if not device:
        return {"success": False, "message": "无已连接设备"}
    params = mgr.get_cached_image_params(device["ip"])
    return {"success": True, "ip": device["ip"], "params": params}

