async def get_device_function(device_id: str) -> dict:
    """从 data/{device_model}/*/function.json 读取设备功能参数范围。"""
    import json
    from pathlib import Path
    mgr: PTZManager | None = _managers.get("ptz_manager")
    if not mgr:
        return {"success": False, "message": "PTZManager 未初始化"}
    
    target_ip = _resolve_device_id_to_ip(mgr, device_id)
    if not target_ip:
        return {"success": False, "message": f"无法解析设备标识: {device_id}"}
    
    # 从 data 目录查找 function.json
    data_dir = Path(__file__).resolve().parent.parent.parent / "data"
    if not data_dir.exists():
        return {"success": False, "message": "data 目录不存在", "data": None}
    
    # 遍历所有子目录查找 function.json
    for subdir in data_dir.iterdir():
        if subdir.is_dir():
            for f in subdir.rglob("function.json"):
                try:
                    with open(f, "r", encoding="utf-8") as fh:
                        func_data = json.load(fh)
                    # 检查 IP 是否匹配
                    if func_data.get("device_info", {}).get("ip") == target_ip:
                        return {"success": True, "data": func_data}
                except Exception:
                    continue
    
    return {"success": False, "message": "未找到该设备的 function.json", "data": None}


