def _save(self) -> None:
    """持久化数据到 JSON 文件。

    ptz_config.json 格式:
    {
        "devices": {
            "MAC": {ip, username, password, port, model, ...}
        }
    }
    """
    with self._lock:
        # ptz_config.json 格式: devices 是 dict
        devices_dict = {}
        for mac, dev in self._devices.items():
            dev_data = {
                "ip": dev.ip,
                "name": dev.name,
                "model": dev.model,
                "status": dev.status,
                "registered_at": dev.registered_at,
                "last_heartbeat": dev.last_heartbeat,
            }
            # 合并 metadata 中的字段
            if dev.metadata:
                dev_data.update(dev.metadata)
            devices_dict[mac] = dev_data

        data = {
            "devices": devices_dict
        }

        tmp_path = self._storage_path.with_suffix(".tmp")
        with open(tmp_path, "w", encoding="utf-8") as f:
            json.dump(data, f, indent=2, ensure_ascii=False)
        tmp_path.replace(self._storage_path)
        log.info(f"设备数据已保存: {len(self._devices)} 台设备")

def _load(self) -> None:
    """从 JSON 文件加载设备数据。

    ptz_config.json 格式:
    {
        "devices": {
            "MAC": {ip, username, password, port, model, ...}
        }
    }
    """
    if not self._storage_path.exists():
        log.info(f"设备存储文件不存在，初始化空状态: {self._storage_path}")
        return

    try:
        with open(self._storage_path, "r", encoding="utf-8") as f:
            data = json.load(f)

        # ptz_config.json 格式: devices 是 dict
        devices_data = data.get("devices", {})
        if isinstance(devices_data, dict):
            for mac, dev_data in devices_data.items():
                norm_mac = _normalize_mac(mac)
                # 提取 metadata 字段
                metadata = {}
                for key in ["username", "password", "port", "serial_number", "serial", "firmware_version", "connected", "last_updated"]:
                    if key in dev_data:
                        metadata[key] = dev_data[key]

                # 构建 Device 对象
                dev = Device(
                    mac=norm_mac,
                    ip=dev_data.get("ip", ""),
                    name=dev_data.get("name", ""),
                    model=dev_data.get("model", ""),
                    status=dev_data.get("status", "offline"),
                    metadata=metadata
                )
                self._devices[norm_mac] = dev
            log.info(f"加载设备数据: {len(self._devices)} 台设备")
        else:
            # 旧格式兼容: devices 是数组
            for d in devices_data:
                mac = _normalize_mac(d.get("mac", ""))
                if mac:
                    self._devices[mac] = Device(**d)
            log.info(f"加载设备数据(旧格式): {len(self._devices)} 台设备")

    except Exception as e:
        log.warning(f"加载设备数据失败，使用空状态: {e}")

